@module coordinator  src=coordinator.lua  loc=363  sha=e2be081  mode=chunk  self=coord
@deps cm, ds, eventMeta, cmgr, gui

# Invariants & contracts
  @invariant  owns the active tracker take; polls REAPER's selection each frame while tracker page is active (sticky on no-item or non-MIDI)  @ 3
  @invariant  no teardown path — quit() sets a flag that stops scheduling further defers; REAPER reclaims state on script unload  @ 4
  @invariant  each deferred frame xpcalls via coord:run's handler; reaper.defer drops the xpcall  @ 5

# Shapes
  @shape  page = { toolbarSegments(), renderBody(ctx,w,h,dispatch), renderStatusBar(ctx), bind(...), unbind() }  @ 284

