# Private functions
  -- Coordinator
  @fn tick()  @ 63-68
      @contract  tick() runs once per frame before the page draws; no selection bus here  @ 62
  @fn drawSwitcher()  @ 70-92
  @fn dispatch(state)  @ 98-105
